/**
 * Profession-level deduction profiles.
 *
 * Twenty-three trades from the verified dataset's `professionals` block, each
 * with the deductions that actually move its Schedule C. No new research: the
 * deduction lists, the profession notes and the unique rules (clergy housing
 * allowance, farm Schedule F) are the dataset's own.
 *
 * WHAT IS AUTHORED HERE AND WHAT IS NOT. The dataset stores deductions as slugs
 * — `client_gifts_limit_25`, `camera_lenses_section179`. Turning those into
 * readable labels is presentation, the same call already made for platform
 * names. What is NOT authored is any figure: where a slug names a rule with a
 * number behind it, that number is read from selfEmploymentDeductions, never
 * typed in. Slugs with no figure behind them get a label and nothing more.
 *
 * NO INVENTED INCOMES. There is no "typical earnings" figure for any of these
 * trades in the dataset, so none is asserted. What the pages compute instead is
 * what a dollar of deduction is worth, which is real arithmetic on real rates
 * and is the number that actually helps.
 */
import { selfEmploymentDeductions, federal } from '../data/federal';
import professionalsData from '../data/professionals';
import { calcFederalTax, calcStateTax, calcSETax, calcQBI, getStandardDeduction, formatMoney } from './tax-engine';

const SED = selfEmploymentDeductions as Record<string, any>;
const RAW = professionalsData as Record<string, any>;

export interface Profession {
  slug: string;
  key: string;
  name: string;
  /** One line naming what this trade specifically gets wrong. Authored. */
  lead: string;
  /**
   * A second authored paragraph, specific to this trade.
   *
   * It exists for a measured reason. Trades with near-identical deduction lists
   * — a hair stylist and a massage therapist both pay booth rent and carry
   * liability insurance; a developer, a VA and a QA tester all live on a home
   * office and a laptop — produced pages that were 73% the same document. The
   * shared part is real and cannot be removed. So the differentiator has to be
   * the part only this trade's reader needs.
   */
  watch: string;
}

/**
 * Order and naming are presentation. `lead` is the one authored sentence per
 * trade, and it exists so that twenty-three pages do not open identically —
 * each names the mistake that is particular to that work.
 */
export const PROFESSIONS: Profession[] = [
  { key: 'software_dev', slug: 'software-developer', name: 'Software developer', lead: 'The home office is the biggest line and the one most contractors underclaim, because they work from a room they also sleep near and assume that disqualifies it. Exclusive use means the space, not the building.', watch: 'Contract developers are the classic reclassification target: if a single client sets your hours, supplies your machine and reviews your work like a manager, the IRS may decide you were an employee, and the 1099 does not settle it. The other line to watch is R&D software, which OBBBA lets you expense in the year of cost rather than amortize.' },
  { key: 'ai_consultant', slug: 'ai-consultant', name: 'AI consultant', lead: 'Compute is the unusual line. GPU hours and API spend are ordinary business expenses in the year incurred, and they can dwarf every other deduction in a month where a model is being trained.', watch: 'Compute spend is uneven in a way that disrupts quarterly estimates: a quarter where you train a model can swing profit by more than your cushion. Base your quarterly payments on last year\u2019s tax bill rather than on a forecast of this year\u2019s and the swing stops mattering \u2014 paying what last year required protects you from a penalty however the year turns out.' },
  { key: 'designer', slug: 'designer', name: 'Designer', lead: 'The hardware is the Section 179 opportunity and the software is the boring line that adds up faster. A monitor and an iPad bought for client work can be expensed in full the year they are placed in service.', watch: 'Stock assets and fonts are licenses, not purchases, and a perpetual license bought for one client project is still an ordinary expense in the year you buy it. Subcontracted illustration or motion work over $600 in a year means you are the one issuing a 1099-NEC.' },
  { key: 'copywriter', slug: 'copywriter', name: 'Copywriter', lead: 'Almost every deduction is a subscription, which means almost every deduction is on a card statement rather than a receipt. That is easier to substantiate, not harder — but only if the card is a business card.', watch: 'Research subscriptions are deductible; the newspaper you would read anyway is not, and the distinction is business purpose rather than content. If you are paid per project rather than retained, watch the year-end timing — a December invoice paid in January is next year\'s income on the cash basis.' },
  { key: 'realtor', slug: 'real-estate-agent', name: 'Real estate agent', lead: 'Client gifts are capped at $25 per recipient per year, and closing gifts routinely cost more than that. The excess is not deductible, however good the intention.', watch: 'Almost every agent is treated as self-employed by law even when working under a brokerage, which means nothing is withheld from a commission check and the whole tax bill arriving at once. Desk fees, brokerage splits and MLS dues come off gross commission, and staging costs you fund yourself are deductible where the seller reimburses you they are not.' },
  { key: 'travel_nurse', slug: 'travel-nurse', name: 'Travel nurse', lead: 'The per diem and the tax home decide everything. Stipends are only tax-free while you have a genuine tax home you are travelling away from — lose that, and the untaxed portion of every stipend becomes income.', watch: 'The tax home determines the outcome. Duplicating expenses — keeping a place you genuinely pay for while you are away — is what makes the untaxed portion of a stipend untaxed. Take a permanent assignment in one place for more than twelve months and the tax home moves there, retroactively.' },
  { key: 'truck_driver_otr', slug: 'truck-driver', name: 'OTR truck driver', lead: 'The DOT per diem is worth more than most drivers claim: $80 a day, deductible at 80% under the hours-of-service rules, for every night away from home.', watch: 'Owner-operators and lease-purchase drivers are self-employed; company drivers on a W-2 are not, and the W-2 driver lost the per diem deduction entirely when miscellaneous itemized deductions went away. Truck depreciation and the per diem are the two biggest lines, and the per diem needs only a log of nights out.' },
  { key: 'photographer', slug: 'photographer', name: 'Photographer', lead: 'Bodies and glass are Section 179 property, and the trap is the business-use test — gear that shoots family holidays as well as weddings only qualifies above 50% business use, at the business percentage.', watch: 'Second shooters and assistants paid over $600 in a year need a 1099-NEC from you. Wedding deposits are income when received on the cash basis even though the wedding is next June, which is why a booked-out spring makes for a painful April.' },
  { key: 'hair_stylist', slug: 'hair-stylist', name: 'Hair stylist', lead: 'Two things changed for 2026 in your favour: up to $25,000 of tips is now deductible, and the employer credit for payroll tax on tips — once restricted to restaurants — was extended to hair care. Booth rent remains the deduction that also makes you self-employed: pay rent for your chair and nobody is withholding anything for you.', watch: 'Booth rent tells you which side of the line you are on: pay rent and take your own clients and you are running a business; take a cut of the salon\'s tickets on the salon\'s schedule and you may be an employee whatever your contract says. Tips are income either way and are the line most often left off. The new deduction reduces income tax only — self-employment tax still applies to every tipped dollar — it phases out above $150,000, and if you are self-employed it cannot exceed the net income of the business. The employer credit is a different thing again and is worth nothing unless you have staff on payroll.' },
  { key: 'personal_trainer', slug: 'personal-trainer', name: 'Personal trainer', lead: 'Trainers are on Treasury\'s list of tipped occupations, so up to $25,000 of tips is deductible for 2026 — income tax only, not self-employment tax. Separately: your own gym membership is deductible at the business-use percentage, and training your own body is not business use. The membership you need to reach clients is; the one you use at 6am is not.', watch: 'Training clients in a gym you pay to access is different from training in your own space: the first makes the membership a business cost at the business-use percentage, the second makes it a personal one. Online coaching sold as a program rather than sessions can raise a sales tax question in some states that in-person training does not.' },
  { key: 'therapist', slug: 'therapist', name: 'Therapist', lead: 'Once you are licensed, supervision hours are a deductible professional expense. The identical spend before you qualify is not deductible at all, because it is training for work you cannot yet do.', watch: 'One rule hits therapists harder than most trades. The 20% deduction for business profit is withdrawn above an income threshold for work where the main asset is the skill of the person doing it — and health counts. Above the threshold it shrinks; higher still, it goes entirely. Sliding-scale fees you choose not to charge are not a deduction; they are simply income you did not earn.' },
  { key: 'nurse_contractor', slug: 'nurse-contractor', name: 'Contract nurse', lead: 'Scrubs are deductible where ordinary clothing is not, because they fail the suitable-for-everyday-wear test. The shoes usually do not.', watch: 'Agency contracts vary on who carries the malpractice cover, and premiums you pay yourself are deductible while premiums the agency pays are not yours to claim. Licensing in multiple states adds up fast for anyone taking assignments across state lines, and each state\'s fee is deductible in the year paid. If you are working in a state you do not live in, you will owe a non-resident return there as well as a resident return at home — the credit for tax paid elsewhere usually prevents double tax, but only if you file both.' },
  { key: 'massage_therapist', slug: 'massage-therapist', name: 'Massage therapist', lead: 'Massage therapy is on Treasury\'s list of occupations whose tips qualify for the new 2026 deduction, which matters in a trade where a large share of income is tipped and almost none of it is reported by anyone else. The table, meanwhile, is Section 179 property deductible in full the year you buy it rather than over seven.', watch: 'Table, linens and oils are the obvious lines and the liability cover is the one people forget to claim after the first year. If you rent a room in a chiropractic or wellness practice, check whether your agreement is rent or a revenue split — a split can make you an employee of the practice.' },
  { key: 'bookkeeper_accountant', slug: 'bookkeeper', name: 'Bookkeeper or accountant', lead: 'You will do this correctly for clients and badly for yourself. The licensing fees an EA or CPA pays are deductible professional expenses and are the line most often left off an own-business return.', watch: 'The same rule that hits therapists hits you: the 20% deduction for business profit is withdrawn above an income threshold for work whose main asset is the skill of the person doing it, and accounting counts. Professional indemnity cover and EA or CPA licensing are both ordinary expenses, and the software you resell to clients is income to you before it is a deduction.' },
  { key: 'virtual_assistant', slug: 'virtual-assistant', name: 'Virtual assistant', lead: 'Almost the entire cost base is home office and technology, which is unusually deduction-friendly — and it means the S-corp question arrives earlier here than in trades with real overheads.', watch: 'With almost no overheads, profit is close to revenue, which brings the S-corp arithmetic forward — the payroll saving starts to beat the payroll cost at a lower revenue here than in trades that buy equipment. Subcontracting overflow work to other VAs makes you a payer: over $600 in a year and you are issuing the 1099.' },
  { key: 'coach', slug: 'coach', name: 'Coach', lead: 'Certification is deductible if it maintains or improves the skills of a business you already have, and not deductible if it qualifies you for the coaching career you are about to start. The same course, two different answers.', watch: 'Selling a program rather than an hour changes the timing: money taken up front for a six-month container is income when received on the cash basis, not when the sessions happen. Coaching is not a licensed profession federally, but calling yourself a therapist or giving financial advice for a fee moves you into regulated territory.' },
  { key: 'insurance_agent', slug: 'insurance-agent', name: 'Insurance agent', lead: 'Commissions are self-employment income, and lead generation is the largest controllable deduction. Captive agents may be on a W-2 for the same work, which changes everything about how it is taxed.', watch: 'Advance commissions that later charge back are the recurring headache — you were taxed on the advance in the year you got it, and the chargeback is a deduction in the year it happens, which may be a different year at a different rate. Lead spend is fully deductible and is usually the largest number you control.' },
  { key: 'notary_signing_agent', slug: 'notary-signing-agent', name: 'Notary signing agent', lead: 'Mileage between signings is the single largest deduction in this trade, and it is the one nobody tracks, because each trip feels too small to write down.', watch: 'The mileage is the deduction and the tracking is the problem: signings are short trips, and untracked short trips are how thousands of dollars of deduction disappear. Notary fees set by state statute are sometimes treated differently from the signing-agent fee charged on top, so bill them as separate lines.' },
  { key: 'tutor', slug: 'tutor', name: 'Tutor', lead: 'Online and in person are different deduction profiles for the same job: online tutors live on the home office, in-person tutors live on mileage between students.', watch: 'If you tutor a family\'s children in their home on a schedule they set, the household may technically be your employer rather than your client. Working through a platform does not change your obligation to report the income — a platform below the 1099-K threshold reports nothing and you still owe.' },
  { key: 'wedding_event_planner', slug: 'wedding-planner', name: 'Wedding and event planner', lead: 'Money you collect for vendors is not your income, and money you pass to vendors is not your deduction. Run both through your books and you will report a business several times the size of the one you have.', watch: 'Ask one question of every payment: is this mine? Deposits held for vendors are not income, vendor invoices you pass on are not deductions, and only your planning fee is either. Get it wrong and your gross receipts look several times larger than your business, which changes your 1099-K, your state registration thresholds and your bookkeeping all at once.' },
  { key: 'qa_tester_contractor', slug: 'qa-tester', name: 'QA tester', lead: 'The device wall is the deduction. Phones and tablets bought to test on are Section 179 property at their business-use percentage, and the percentage is what gets argued about.', watch: 'The business-use percentage on the test devices is the argument you should prepare for: a phone used for testing and for your own calls is a split, and 100% on a device you plainly also carry personally is the claim that draws attention. Contract QA is also heavily agency-mediated, so check whether your contract makes you the agency\'s employee. Most contract QA is booked through an agency, and the agency decides more than the rate: some engage you as a contractor and some as their own employee for the same work, and only the first lets you deduct any of this. Check which you are before assuming a home office is available to you. Test devices bought and then kept for personal use after the contract ends should have the business-use percentage revisited rather than left at the original figure.' },
  { key: 'clergy_minister', slug: 'clergy', name: 'Clergy and ministers', lead: 'The housing allowance is excluded from income tax and included in the self-employment tax base. Ministers are employees for income tax and self-employed for SE tax on the same money — the only place in the code this happens.', watch: 'The dual status means no employer withholds self-employment tax from your salary even though you get a W-2, so quarterly estimates are on you from the first year. Opting out with Form 4361 is irrevocable and available only on conscientious religious grounds, not on the arithmetic — and it gives up Social Security credits permanently.' },
  { key: 'farm_schedule_f', slug: 'farmer', name: 'Farmer', lead: 'Schedule F, not Schedule C, and the difference is not cosmetic: raised livestock carries no basis, purchased livestock is cost of goods sold, and breeding animals are depreciable assets rather than an expense.', watch: 'Farm income averaging on Schedule J lets you spread an exceptional year back across the three prior years, which no other trade here can do. Crop insurance proceeds can be deferred a year where the crop would normally have been sold in the following year, and prepaid feed and supplies are limited to half your other deductible farm expenses.' },

  /* Building, mechanical, teaching and personal-service trades. These are not in
     the legacy dataset — see overrides/professions-trades.json for the boundary. */
  { key: 'general_contractor', slug: 'general-contractor', name: 'General contractor', lead: 'Subcontractors decide this return. Pay anyone $600 or more in a year and you have to issue them a 1099-NEC, and treating someone as a subcontractor when the law says employee is the most expensive mistake available in this trade.', watch: 'Materials you buy and bill on are income and a deduction both — book only one and your return is wrong in a way that is obvious from the outside. Retainage held back by a customer is not yours until released, so on the cash basis it is not income until you actually receive it.' },
  { key: 'electrician', slug: 'electrician', name: 'Electrician', lead: 'Hand tools and testers come off in the year you buy them. A van fit-out does not — that is an improvement to the vehicle and is written down over years, which surprises people who bought both in the same week.', watch: 'Your state license and the continuing education hours that renew it are both deductible, because they maintain a license you already hold. The apprenticeship that got you the license in the first place was not, for the same reason in reverse. Service work and new construction are different businesses for tax purposes even when the same van does both: new construction is usually contracted through a builder who pays on 30 to 60 day terms, so on the cash basis a job finished in December can be next year\'s income. Panel upgrades and EV charger installations often attract customer rebates, and a rebate paid to the customer is not your income even when it passes through your invoice.' },
  { key: 'plumber', slug: 'plumber', name: 'Plumber', lead: 'Emergency call-outs make mileage the biggest single deduction in this trade, and the least well recorded. A drive at 2am is worth exactly the same per mile as one at 2pm, and neither counts if it is not written down.', watch: 'Drain cameras, jetters and press tools are Section 179 property — the whole cost comes off in the year the tool goes into service rather than being spread across its life. Parts bought for a job are deductible when used; a van full of stock at December 31 is inventory, not an expense. Water damage callouts put you in the insurance chain, and money an insurer pays you directly is your income while money it pays the homeowner is not — the difference decides whether it belongs on your return at all. Backflow certification and medical gas endorsements are separate qualifications with separate renewal fees, and each renewal is deductible.' },
  { key: 'hvac_technician', slug: 'hvac-technician', name: 'HVAC technician', lead: 'EPA Section 608 certification and the state license behind it are deductible professional costs, as is every renewal. They maintain a qualification you already have, which is the test that matters.', watch: 'Refrigerant and parts are deductible when they go into a job, not when they go into the van. Diagnostic equipment and recovery machines are Section 179 property and can be written off in full the year you start using them.' },
  { key: 'landscaper', slug: 'landscaper', name: 'Landscaper', lead: 'Mowers, trimmers and trailers are Section 179 property, so a season\'s equipment buying can come off in a single year rather than being spread across several.', watch: 'Seasonal crews are usually employees, not contractors. Paying weekly, setting the schedule and supplying the equipment all point one way, and the penalty for calling them contractors anyway is back payroll tax with interest. Fuel for equipment is an ordinary supply and is separate from vehicle mileage.' },
  { key: 'cleaner', slug: 'cleaner', name: 'Cleaner', lead: 'Mileage between client properties counts. The first drive of the day from home to your first job does not — that is commuting, and it stays commuting however early it is and however far you go.', watch: 'Bonding and liability cover are what clients ask to see before they hire you, and both are deductible. Supplies are straightforward; equipment above a few hundred dollars is worth treating as Section 179 property so it comes off in one year.' },
  { key: 'handyman', slug: 'handyman', name: 'Handyman', lead: 'Most handyman work sits below the state licensing threshold, but the threshold is set by each state and usually by the value of the individual job. Go over it without a license and the work can be uninsured and the contract unenforceable.', watch: 'Materials billed to the customer are income and a deduction both. Tools are deductible in the year you buy them, and the mileage between jobs is worth logging — a scattered day of small jobs adds up faster than a single long drive.' },
  { key: 'painter', slug: 'painter', name: 'Painter', lead: 'Sprayers, scaffolding and lifts are usually cheaper to hire than to own, and hire costs come off in full in the year you pay them with no depreciation schedule to keep.', watch: 'Paint and materials bought for a specific job are deductible when used. Interior work is year-round and exterior work is not, so painters carry an uneven income across the year that makes quarterly estimates awkward — base them on last year\u2019s bill rather than a forecast and the seasonality stops mattering. Lead-safe certification for pre-1978 properties is a federal requirement on much residential repainting, and both the certification and its renewal are deductible.' },
  { key: 'roofer', slug: 'roofer', name: 'Roofer', lead: 'Workers\' compensation is the largest insurance cost in roofing by a wide margin — the rates are the highest of any building trade because the injury rates are. It is fully deductible, and it is not optional once anyone works for you.', watch: 'Fall-protection equipment is both a legal requirement and an ordinary business expense, so there is no tension between the two. Storm work is the tax problem peculiar to roofing: a hail season can double a year\u2019s income and push you into brackets a normal year never reaches, and insurance proceeds paid directly to a homeowner are their money rather than yours. Tear-off dumpsters and crane hire are deductible in full in the year of hire.' },
  { key: 'welder', slug: 'welder', name: 'Welder', lead: 'Certifications expire and every renewal is deductible, because it maintains a qualification you already hold rather than getting you a new one.', watch: 'Gas, rod and consumables are ordinary supplies deductible as you use them. The machine is Section 179 property and comes off in full the year it goes into service. If you weld on site, the mileage to each job is deductible and the drive from home to a regular shop is not. Rig welders are the specific case worth flagging: if you own the truck and the machine and hire both to a contractor with your labor, the rig rental portion and the labor portion can be treated differently, and getting that split documented before the job rather than after is what makes it hold up. Certification tests are usually paid for by you and are deductible, including the ones you fail.' },
  { key: 'auto_mechanic', slug: 'auto-mechanic', name: 'Auto mechanic', lead: 'Tool debt defines this trade. Tools bought on a truck account are deductible when you buy them, not when you finish paying for them — and the interest on the account is deductible separately, on top.', watch: 'Shop rent, waste oil disposal and uniforms are all ordinary expenses. Certifications are deductible as maintaining existing skills once you are working in the trade, which is why the same course is treated differently for an apprentice.' },
  { key: 'teacher_tutor', slug: 'teacher', name: 'Teacher', lead: 'The $300 educator expense deduction is for employed teachers in a school, and it is a ceiling. If you teach for yourself — private tuition, online courses, music lessons — you are not limited to $300 at all. You deduct what you actually spent as a business expense, which is nearly always more.', watch: 'Materials, a laptop, the platform subscriptions and the room you teach from are all ordinary business expenses. If you teach in person, the mileage between students is deductible; if you teach online, the home office usually becomes the largest line on the return.' },
  { key: 'musician', slug: 'musician', name: 'Musician', lead: 'Instruments are Section 179 property, so a professional instrument comes off in the year you start using it. If you also play it at home for pleasure, you deduct at the business-use percentage rather than in full.', watch: 'Touring costs are business travel and deductible, but meals within them are only half deductible. Union dues and professional memberships are deductible; so is the cost of recording and releasing work, which many players treat as a hobby cost and never claim.' },
  { key: 'translator', slug: 'translator', name: 'Translator', lead: 'Translation memory and terminology software are ordinary subscriptions, deductible in the year you pay for them, and they are usually the largest recurring cost in the work.', watch: 'Certification through a professional body is deductible where you are already working in the field, because it improves an existing skill. Taken before you start translating professionally, the same certification is qualifying you for new work and is not deductible. Most translation clients are abroad, which brings two things a domestic freelancer never meets. Payment platform and currency conversion fees are ordinary deductible costs and can quietly reach several percent of turnover. And foreign clients do not issue you a 1099 of any kind, so nothing arrives to remind you of the income — you still owe tax on all of it, and the absence of paperwork is not the absence of an obligation.' },
  { key: 'videographer', slug: 'videographer', name: 'Videographer', lead: 'Cameras, lenses, drones and lighting are Section 179 property at the business-use percentage — and the percentage is the part that gets argued about, because the same camera films weddings and family holidays.', watch: 'Hiring gear for a single shoot sidesteps that argument completely: hire cost is deductible in full with no business-use split and nothing to depreciate. Editing software, storage and color tools are ordinary subscriptions.' },
  { key: 'dog_groomer', slug: 'dog-groomer', name: 'Dog groomer', lead: 'A mobile groomer has two different tax treatments inside one vehicle: the van conversion is an improvement to the vehicle and is depreciated, while the grooming equipment inside it is Section 179 property in its own right.', watch: 'Shampoos and consumables are supplies. Liability cover is what most premises and clients require and is deductible. Certification is deductible where it maintains skills you already use professionally. Retail sales change the shape of the return. Selling shampoo, brushes or treats alongside the grooming makes part of your income product sales with cost of goods sold against it, and in most states it also creates a sales tax obligation that the grooming service itself does not. Boarding or daycare added on top brings its own insurance requirement.' },
  { key: 'caterer', slug: 'caterer', name: 'Caterer', lead: 'Food bought for a job is cost of goods sold rather than a general expense, which changes where it appears on your return even though it still reduces your profit.', watch: 'The 50% limit on business meals does not touch it. That limit is about meals you eat while working, not food you buy to sell — a distinction worth being clear about, because applying the wrong one halves a very large number. Permits, food-handling certification and equipment hire are all ordinary expenses.' },

  /* Practices, agencies, trades and operators added after the first two passes.
     Like the trades above these are authored, not ported — see the overlay. Each
     leads with what is genuinely different about its tax position rather than
     with a generic Schedule C opening. */
  { key: 'physician_practice', slug: 'physician', name: 'Physician in private practice', lead: 'The 20% deduction for business profit does not survive at a consultant\'s income. Medicine is one of the trades where it phases out above a threshold and then disappears — which is why practice owners talk about entity structure far more than other business owners do.', watch: 'Medical equipment is Section 179 property and a practice fit-out can be written off far faster than most owners expect, including a cost segregation study on a building you own. Malpractice cover is deductible in the year you pay it, and a tail policy bought when you leave a practice is deductible too. Staff are employees rather than contractors in almost every case — a nurse working your hours in your rooms with your equipment is not a contractor whatever the agreement says.' },
  { key: 'dentist', slug: 'dentist', name: 'Dentist or orthodontist', lead: 'Dentistry is the most equipment-heavy of the professional practices. A chair, a cone beam scanner and a practice fit-out are Section 179 property, and expensing them in one year rather than over seven changes the tax on a good year completely.', watch: 'Lab fees are cost of goods rather than an overhead, which matters for how the return reads. Dentistry is also a specified service trade, so the 20% business profit deduction is withdrawn above an income threshold — the equipment deductions keep working at every income, the profit deduction does not.' },
  { key: 'veterinarian', slug: 'veterinarian', name: 'Veterinarian', lead: 'A veterinary practice is two businesses in one return. The consulting is a service; the drugs, food and products sold over the counter are goods, with inventory and cost of goods sold against them, and in most states they carry sales tax the consultation does not.', watch: 'Controlled drug storage, sharps and clinical waste disposal are ordinary deductible costs and are also regulatory requirements. Veterinary medicine counts as a health field for the 20% business profit deduction, so that deduction is withdrawn above an income threshold. Mobile and large-animal practice makes the vehicle a major line — and a truck fitted out for veterinary work is usually a business vehicle in full rather than a percentage.' },
  { key: 'chiropractor', slug: 'chiropractor', name: 'Chiropractor', lead: 'Chiropractic carries a marketing budget that other health practices do not, and it is fully deductible. Screenings, community events and advertising are ordinary business costs; the retail supplements sold alongside are goods, with inventory rules and usually sales tax.', watch: 'Tables, decompression equipment and imaging are Section 179 property. Chiropractic is a health field for the 20% business profit deduction, so it is withdrawn above an income threshold. Practice-management and billing software is an ordinary subscription, and the merchant fees on care plans paid monthly are deductible and easy to overlook.' },
  { key: 'aba_provider', slug: 'behavioral-health-practice', name: 'Behavioral health practice owner', lead: 'Payroll dominates this return. Behavior technicians and analysts working your hours, to your treatment plans, under your supervision are employees — the classification question is not close, and treating them as contractors is the most expensive mistake available here.', watch: 'In-home and school-based sessions make mileage a major deduction, and it is the one least well tracked because each drive is short. Credentialing with each insurer costs money and takes months, and both the fees and the consultant who handles them are deductible. Behavioural health is a health field for the 20% business profit deduction, so it is withdrawn above an income threshold.' },
  { key: 'home_health_agency', slug: 'home-health-agency', name: 'Home health agency owner', lead: 'Caregivers are employees, and payroll with the employer taxes on it is deductible in full. The overtime position is genuinely unsettled right now: a 2013 rule stopped agencies claiming the companionship and live-in exemptions and was upheld in court, but the Department of Labor stopped enforcing it in 2025 and has proposed rescinding it. The rule is still law, so private claims and state wage laws still apply — do not read non-enforcement as permission.', watch: 'Background checks, training hours and state licensing are all deductible. Caregiver mileage between clients is deductible to whoever bears it — reimburse it and the agency deducts it, do not and the caregiver may claim it themselves. Scheduling and electronic visit verification software are ordinary subscriptions and are usually mandatory for Medicaid billing.' },
  { key: 'staffing_agency', slug: 'staffing-agency', name: 'Staffing or recruiting agency owner', lead: 'A staffing agency deducts wages for people who never set foot in its own office. You are the employer of record, so payroll tax, unemployment insurance and workers\' compensation sit on your return — and workers\' compensation is rated on what the placed worker does, not on what you do, so placing roofers costs many times what placing bookkeepers does.', watch: 'Placement fees are income when earned, and a guarantee period that forces a refund creates a deduction in the year you repay rather than a correction to the original year. Applicant tracking software, job board spend and background checks are ordinary deductible costs. And unlike most professional service firms, a staffing business that sources and refers candidates is not treated as consulting — so the 20% business profit deduction survives at incomes where a consultancy would lose it. Sell advice and counsel rather than placements and that changes.' },
  { key: 'attorney', slug: 'attorney', name: 'Attorney or law firm partner', lead: 'Money in the client trust account is not yours and never appears on your return until it is earned and transferred. Running trust funds through operating income is both a tax error and a bar complaint, and it is the single thing regulators look at first.', watch: 'Case costs advanced on a client\'s behalf are loans rather than deductions until the case resolves and they prove unrecoverable — a contingency practice can carry six figures of advanced costs that are not yet deductible at all. Law is a specified service trade, so the 20% business profit deduction is withdrawn above an income threshold. Bar dues, research subscriptions and continuing legal education are all deductible.' },
  { key: 'tax_preparer', slug: 'tax-preparer', name: 'Tax preparer or enrolled agent', lead: 'Your income arrives in a quarter and your costs run all year. That makes your own estimated payments the awkward case you spend the spring solving for other people — base them on last year\'s bill rather than a forecast and the seasonality stops mattering.', watch: 'PTIN renewal, e-file provider fees, continuing education hours and enrolled agent or CPA licensing are all deductible as maintaining a qualification you already hold. Professional indemnity cover is effectively mandatory and deductible. Tax preparation is a specified service trade, so the 20% business profit deduction is withdrawn above an income threshold.' },
  { key: 'financial_advisor', slug: 'financial-advisor', name: 'Financial advisor', lead: 'Compliance is a cost center with no equivalent in most businesses. Registration, the annual audit, email and message archiving, and a compliance consultant are all deductible, and none of them are optional once you are advising for a fee.', watch: 'Custodial and platform fees you absorb rather than pass on are deductible; fees deducted from a client\'s account are never your income in the first place. Financial services is a specified service trade, so the 20% business profit deduction is withdrawn above an income threshold — and advisors are unusually likely to be above it.' },
  { key: 'medical_billing', slug: 'medical-billing', name: 'Medical billing service', lead: 'Handling protected health information for other practices makes you a business associate in your own right. Secure systems, signed agreements, encrypted storage and breach cover are legal requirements and ordinary deductible costs at the same time.', watch: 'Cyber liability cover is the deduction most billing services do not carry until a client asks for proof of it. Clearinghouse fees and practice management software are ordinary subscriptions. Payment on a percentage of collections means income moves with the client\'s revenue, so estimates based on last year\'s bill are safer than a forecast.' },
  { key: 'architect', slug: 'architect', name: 'Architect', lead: 'Architecture is written into the statute as an exception. The 20% deduction for business profit is withdrawn at higher incomes for law, accounting, medicine and consulting — and explicitly not for architecture. A successful architectural practice keeps a deduction an equally successful law firm loses.', watch: 'Professional liability cover is the dominant insurance cost and is deductible, including the tail cover that runs after a project completes. Design software licenses are ordinary subscriptions. Travel to sites is business travel; the drive to your own studio is commuting.' },
  { key: 'engineer', slug: 'engineer', name: 'Engineering firm owner', lead: 'Engineering is the other statutory exception. Where medicine, law and accounting lose the 20% business profit deduction above an income threshold, engineering keeps it — a distinction worth real money and one that surprises engineers who have read general advice for professionals.', watch: 'Multi-state work creates filing obligations in every state you practice in, and professional registration in each is separately deductible. Testing and survey equipment is Section 179 property. Professional liability cover, including tail cover, is deductible in the year you pay it.' },
  { key: 'interior_designer', slug: 'interior-designer', name: 'Interior designer', lead: 'Buying furnishings and reselling them makes you a retailer with inventory, cost of goods sold and usually a sales tax obligation. Taking a commission on what the client buys directly makes you a service business with none of that. Most designers do both, and running them through one account is what makes the return unpickable later.', watch: 'Client deposits for goods not yet ordered are not income until earned. Samples, fabric books and showroom memberships are ordinary costs. Photography of finished projects is marketing and fully deductible — it is also the only asset most design practices have.' },
  { key: 'home_stager', slug: 'home-staging', name: 'Home staging business', lead: 'Your furniture is not stock you sell, it is equipment you hire out repeatedly — which makes it a depreciable asset rather than inventory, and Section 179 lets you write it off in the year you buy it rather than across its life.', watch: 'Warehouse rent is usually the second largest line and is deductible in full. Moving crews are employees more often than contractors. Staging on consignment, where you take a share of the sale price, is income when the property sells rather than when the work is done — which can put the income in a different year from the cost.' },
  { key: 'marketing_agency', slug: 'marketing-agency', name: 'Marketing agency owner', lead: 'Ad spend you place on a client\'s behalf runs through your books as income and as a deduction. It nets to nothing and it makes your gross receipts look like a business ten times the size — which changes your 1099-K, your state registration thresholds and every conversation with a lender. Bill it as a pass-through where you can.', watch: 'Freelancers and contractors are the flexible half of most agency cost bases, and anyone paid $600 or more in a year needs a 1099-NEC from you. Whether the 20% business profit deduction survives at higher incomes turns on what you actually sell: advice and counsel is consulting, which loses it above the threshold, while running campaigns and producing work is not obviously consulting at all. An agency doing both should expect the question.' },
  { key: 'seo_consultant', slug: 'seo-consultant', name: 'SEO consultant', lead: 'The tool stack is the overhead. Rank trackers, crawlers, backlink databases and keyword platforms run to more each month than many consultants pay in rent, and every one of them is deductible in the year you pay for it.', watch: 'Retainers paid in advance are income when received on the cash basis, even where the work runs for six months. Content and link building bought from freelancers is deductible and triggers a 1099-NEC above $600 a year. If you sell advice, that is consulting, and the 20% business profit deduction is withdrawn above the income threshold — $201,750 for a single filer in 2026. Sell delivered work rather than recommendations and the position is less clear-cut.' },
  { key: 'podcaster', slug: 'podcaster', name: 'Podcaster', lead: 'Sponsorship is usually paid up front for episodes that run over months. On the cash basis it is income when it arrives, not when the episode airs — which can put a whole season\'s revenue into one tax year and none into the next.', watch: 'Microphones, interfaces, treatment and cameras are Section 179 property. Editing, hosting and transcription are ordinary subscriptions. Affiliate revenue and listener support are both taxable income even where no form arrives, and platforms below the reporting threshold send nothing at all.' },
  { key: 'writer_author', slug: 'writer', name: 'Writer or author', lead: 'An advance is income the year it lands, not the year the book earns out — and it is normally self-employment income rather than passive royalty income, because writing the book is the trade you carry on. That surprises authors who expected the royalty treatment their contract talks about.', watch: 'Research travel is deductible where the trip is primarily for the book. Agent commission is deductible in full. Writers are exempt from the rule that would otherwise force you to capitalize production costs, so what you spend writing is deductible as you spend it rather than held until publication. Writing is a specified service trade, so the 20% business profit deduction is withdrawn above an income threshold.' },
  { key: 'actor_performer', slug: 'actor', name: 'Actor or performer', lead: 'Agent and manager commissions are deductible in full, and they are taken from gross — so the income on your 1099 is a figure you never actually received. Deduct the commission and the tax follows what you kept.', watch: 'Ongoing classes and coaching are deductible because they maintain skills you already sell. The training that got you started was not. Headshots, reels and submission fees are marketing. Wardrobe is only deductible where it is unsuitable for everyday wear, which almost never covers what you wear to an audition.' },
  { key: 'professional_speaker', slug: 'professional-speaker', name: 'Professional speaker', lead: 'Speaking across state lines creates filing obligations across state lines. Several states withhold tax from a performer or speaker fee before it reaches you, and you recover it only by filing there — which means a year of touring can mean a stack of non-resident returns.', watch: 'Travel to engagements is business travel and deductible in full, apart from meals at half. Showreels, photography and a website are marketing. One widely repeated claim is wrong: the rule about a business whose principal asset is someone\'s reputation or skill is far narrower than it sounds. It reaches endorsement fees, appearance fees and licensing your name, image or voice — not ordinary speaking fees. What can make a speaker\'s income a specified service trade is the content: teaching and advising is consulting, which is one.' },
  { key: 'conference_organizer', slug: 'conference-organizer', name: 'Conference organiser', lead: 'Tickets sell months ahead and the costs land in a single week. On the cash basis the income and the event can fall in different tax years entirely, which turns a break-even conference into a taxable year followed by a loss-making one.', watch: 'Venue deposits are paid long before the event and are deductible when paid. Cancellation insurance is deductible and is what stops a canceled event becoming a personal liability. Sponsorship sold is income; the sponsor\'s own costs passing through your account are not yours in either direction.' },
  { key: 'travel_agent', slug: 'travel-agent', name: 'Travel agent', lead: 'What a client pays for a trip is not your income. Only the commission is, and it usually arrives after travel rather than at booking — so a busy year can be a thin one for cash and the following January can be unexpectedly heavy.', watch: 'Familiarisation trips are deductible where the primary purpose is genuinely business, and the test is what you did rather than where you went. Host agency fees, booking platforms and errors and omissions cover are ordinary deductible costs. Client funds held before departure are not yours and should never sit in an operating account.' },
  { key: 'tour_operator', slug: 'tour-operator', name: 'Tour operator', lead: 'Unlike an agent, you carry the trip. That makes liability cover the defining cost of the business and it is deductible in full — as is the specialist rescue or evacuation cover most permits require.', watch: 'Deposits taken a season ahead are income when received on the cash basis even though the trip has not happened. Permits for public land, guide certification and first aid training are all deductible. Vehicles and equipment used for tours are Section 179 property at the business-use percentage.' },
  { key: 'restaurant_owner', slug: 'restaurant', name: 'Restaurant owner', lead: 'Tipped staff create a credit, not just a cost. You pay employer Social Security and Medicare on tips your staff report, and a federal credit gives most of that back — it is claimed on a separate form and it is the single most commonly missed item in the trade.', watch: 'Food is cost of goods sold rather than an overhead, and the 50% limit on business meals has nothing to do with it — that limit is about meals you eat, not food you sell. Kitchen equipment and a fit-out are Section 179 property, and a building you own can be cost segregated so parts of it depreciate far faster than 39 years. One thing changed against you this year: meals you provide to your own staff stopped being deductible at all in 2026. They were half deductible from 2018 and fully deductible before that, and they are now nothing — though they remain tax-free to the employee eating them.' },
  { key: 'food_truck', slug: 'food-truck', name: 'Food truck owner', lead: 'The truck is a vehicle and a kitchen at once, and the two are deducted differently. Fuel and running costs follow vehicle rules; the build-out, the equipment and the fit inside follow Section 179. Mixing them is the most common error on a food truck return.', watch: 'Commissary rent is required by most health departments and is deductible in full. Permits are per-city and stack up fast for anyone working events across a region, and each is deductible where paid. Food is cost of goods sold. Event pitch fees are ordinary business costs.' },
  { key: 'hotel_owner', slug: 'hotel', name: 'Hotel or motel owner', lead: 'The building is the business and depreciation is the largest deduction on the return. A cost segregation study splits out the parts that are not really building — carpets, fittings, signage, car park surfacing — into much shorter lives, and 100% bonus depreciation is now permanent on the qualifying portion.', watch: 'Hospitality is not a specified service trade, so the 20% business profit deduction is not withdrawn by income alone the way a law or medical practice\'s is. Above the threshold it is still capped by what you pay in wages and what you have invested in property — which a hotel with staff and a building usually clears comfortably. Occupancy taxes you collect are never your income. Renovation is the line that needs care: a repair is deductible now, an improvement is capitalized, and the distinction is governed by rules that reward getting an opinion before the work rather than after.' },
  { key: 'str_host_business', slug: 'short-term-rental-business', name: 'Short-term rental operator', lead: 'The seven-day rule decides everything here. Where average guest stays are seven days or fewer, the property is not a rental activity under the passive loss rules at all — so if you materially participate, losses can offset your other income rather than being locked up until you sell. Longer average stays and the ordinary passive rules apply.', watch: 'Furnishing a unit is Section 179 and bonus depreciation territory, and a cost segregation study on the property itself accelerates a great deal more. Cleaning and turnover costs are ordinary and are the largest recurring line for most operators. Occupancy taxes collected from guests are never your income, whether the platform remits them or you do.' },
  { key: 'ecommerce_seller', slug: 'ecommerce-seller', name: 'E-commerce seller', lead: 'The form reports gross. Your 1099-K shows everything the platform processed before fees, refunds, shipping and the cost of the goods themselves — and reconciling that figure down to actual profit is most of the work on an e-commerce return. Report the gross and deduct the difference; do not report a net figure the form does not match.', watch: 'Inventory is not deductible when you buy it. It becomes cost of goods sold when it sells, which is why a profitable-feeling year with a warehouse full of stock produces a tax bill that makes no sense. Selling into other states creates sales tax obligations once you pass their thresholds, and those thresholds are about your sales rather than your presence.' },
  { key: 'import_export', slug: 'import-export', name: 'Import or export business', lead: 'Duty, freight and insurance to get goods to you are part of the cost of those goods, not separate overheads. That means they are not deductible when paid — they attach to the inventory and come off when it sells. A container that lands in December and sells in March is a next-year deduction.', watch: 'Customs brokers, compliance consultants and trade counsel are ordinary deductible costs. Currency conversion losses on trade payables are deductible; gains are income. Foreign travel primarily for business is deductible with the usual apportionment where the trip mixes purposes.' },
  { key: 'freight_broker', slug: 'freight-broker', name: 'Freight broker', lead: 'What you pay carriers passes through your books and it is most of what you bill. A brokerage turning over millions can be running on a margin of a few per cent, and the gross figure misleads lenders, tax authorities and sometimes the broker.', watch: 'The surety bond required for authority is an ordinary deductible cost, as is contingent cargo cover. Factoring fees, where you sell receivables to fund carrier payments, are deductible in full. Brokerage owns no trucks, so there is very little depreciation here and almost the entire return is operating costs.' },
  { key: 'courier_service', slug: 'courier-service', name: 'Courier or delivery service', lead: 'One van and you are a driver. Several vans and you are an employer — drivers on your routes, in your vehicles, to your schedule are employees in nearly every case, and payroll rather than mileage becomes the dominant deduction.', watch: 'Company vehicles use actual costs rather than the mileage rate, and are depreciated or expensed under Section 179. Commercial auto cover is far more expensive than personal cover and is deductible in full. Routing and proof-of-delivery software are ordinary subscriptions.' },
  { key: 'limo_service', slug: 'limo-service', name: 'Limo or car service operator', lead: 'Vehicle depreciation is the surprise here, and it is a pleasant one. The annual caps that limit what you can write off on an ordinary car apply only to vehicles rated at 6,000 lb or less, so heavier vehicles escape them entirely — and vehicles used directly in the business of carrying people for hire are excluded on their own account. A full-size van or a stretch is treated far more generously than a saloon.', watch: 'Chauffeurs on your schedule in your vehicles are employees. Commercial passenger insurance is the largest fixed cost in the business and is deductible in full, as are the operating authority and per-airport permits. Detailing and presentation costs are ordinary business expenses in a trade sold on presentation.' },
  { key: 'property_flipper', slug: 'property-flipper', name: 'Property flipper', lead: 'This is the misunderstanding that costs the most money in property. A flipper is a dealer, not an investor. The properties are stock, so the profit is ordinary income — not a capital gain, not eligible for the lower long-term rates however long you held it, and not eligible for a like-kind exchange to defer it. Self-employment tax applies on top if you trade as a sole proprietor or a partner, though not to an S-corporation shareholder\'s share.', watch: 'Because the properties are stock rather than assets, you get no depreciation while you hold them, and renovation costs are not deductible as you spend them — they attach to the property and come off when it sells. A rehab running across a year end can produce a tax bill on a project that has not yet paid you anything. Dealer status is decided property by property rather than for you as a person, so the same investor can hold rentals that do qualify for long-term rates alongside flips that do not.' },
  { key: 'car_dealership', slug: 'car-dealership', name: 'Independent car dealer', lead: 'Floor plan interest — the finance on the cars sitting on your lot — has a carve-out of its own from the cap on deducting business interest. That is a rule written for this trade and it is worth real money to any dealer carrying stock on credit.', watch: 'Vehicles are inventory, so nothing is deductible when you buy them and everything comes off as cost of goods sold when they sell. Reconditioning attaches to the car rather than being a period expense. Dealer licensing, bonds and lot insurance are ordinary deductible costs.' },
  { key: 'body_shop', slug: 'body-shop', name: 'Collision repair shop', lead: 'Insurers pay most of your invoices, and the money is yours when the work is done rather than when the claim is agreed. Supplements approved after the fact are income in the year they are paid, which is often a different year from the repair.', watch: 'Manufacturer certification programs — the ones that put you on an approved list — require specific equipment and training, and both are deductible, the equipment under Section 179. Paint, consumables and materials are supplies. Waste paint, solvent and refrigerant disposal are regulated and deductible.' },
  { key: 'security_company', slug: 'security-company', name: 'Security company owner', lead: 'Guard payroll is effectively the whole cost base, and it is where the classification question is decided: guards on your posts, in your uniform, to your post orders are employees. Armed contracts change the economics again — the insurance and the licensing both cost multiples of unarmed work, and both are deductible.', watch: 'Uniforms are deductible because they are unsuitable for everyday wear. State licensing for the company and for each individual guard is deductible, as is the training required to obtain and keep it. Patrol vehicles are business vehicles using actual costs.' },
  { key: 'private_investigator', slug: 'private-investigator', name: 'Private investigator', lead: 'Two costs here have no equivalent elsewhere: the paid databases that make the work possible, and a vehicle chosen to be unmemorable rather than pleasant. Both are ordinary deductible business expenses, and the databases are usually the larger of the two.', watch: 'Surveillance equipment — cameras, long lenses, recorders, trackers where lawful — is Section 179 property. Mileage on surveillance is deductible and is often very high; a log matters more here than in most trades because the pattern of driving looks nothing like ordinary business travel. State licensing and the insurance most licenses require are deductible.' },
  { key: 'winery_brewery', slug: 'winery-brewery', name: 'Winery or brewery owner', lead: 'Federal excise tax is a separate obligation from income tax, owed on what you produce rather than what you earn, and it is payable whether or not the business is profitable. Smaller producers get a reduced rate on the first tranche of production, which is worth confirming rather than assuming.', watch: 'Tanks, fermenters, canning lines and cooperage are Section 179 property. Product in barrel or tank is inventory and is not deductible until sold, which is costly for anything aged across several years. A tasting room is a separate retail business inside the same company, usually with sales tax and its own licensing.' },
  { key: 'cannabis_business', slug: 'cannabis-business', name: 'Cannabis business owner', lead: 'This changed on April 28, 2026 and the answer now depends on your license. Section 280E denies every ordinary business deduction to a trade dealing in a Schedule I or II controlled substance. From that date marijuana held under a state MEDICAL license, and marijuana in an FDA-approved product, moved to Schedule III — so 280E no longer reaches those businesses. Marijuana in any other form, including adult-use, stays Schedule I and 280E still applies to it in full.', watch: 'For an adult-use operator nothing has changed. Rent, wages, marketing, utilities and insurance are not deductible federally, and what survives is cost of goods sold — because that reduces gross receipts to gross income rather than being a deduction from it. That single distinction is why so much turns on how costs are split between production and everything else, and why the split is examined so often. Federal tax ends up charged on a figure far larger than the profit the business actually made. For a medical-licensed operator 2026 is a split year, and the change landed part way through it. There is no IRS guidance yet on how the transition works, whether it applies from the effective date or the whole year, or what it means for earlier returns. Do not assume either answer. New York, California and Colorado already decouple from 280E and allow the deductions on the state return, so a state and federal return can show very different profit whichever schedule you are on. This is not a position to take without specialist advice.' },
  { key: 'mining_operator', slug: 'mining-operator', name: 'Mining or extraction operator', lead: 'Depletion is the deduction that exists nowhere else. You deduct for the resource being used up, and the percentage method is calculated on revenue rather than on what you paid — so over a mine\'s life the total deductions can exceed the original investment.', watch: 'Exploration and development costs have elections attached that decide whether you deduct now or capitalize, and the choice is worth modeling before you make it because it is not freely reversible. Reclamation obligations are deductible when the work is done rather than when the liability arises. Heavy equipment is Section 179 property subject to the annual cap.' },
  { key: 'print_shop', slug: 'print-shop', name: 'Printing or signage shop', lead: 'The equipment is the business and it is expensive: presses, wide-format printers, cutters and finishing gear are all Section 179 property, deductible in the year they go into service rather than across a decade.', watch: 'Paper, vinyl and substrate held at year end are inventory and are not deductible until used. Installation of signage on a customer\'s site can bring licensing and insurance requirements that in-shop printing does not. Color management software and font licensing are ordinary subscriptions.' },
  { key: 'event_rental', slug: 'event-rental', name: 'Event rental company', lead: 'Everything you own goes out and comes back, which makes it depreciable equipment rather than inventory. Section 179 lets you deduct tents, tables, chairs, staging and lighting in the year you buy them rather than across their lives, and that is a very large deduction for a business built entirely on stock.', watch: 'Damage waivers charged to customers are income; the repairs they fund are deductible separately. Delivery crews are employees in nearly all cases. Warehouse or yard rent is the second largest fixed cost and is deductible in full.' },
  { key: 'mobile_mechanic', slug: 'mobile-mechanic', name: 'Mobile mechanic', lead: 'Your van is a workshop that drives, and the two halves are deducted differently: running costs follow vehicle rules, while the racking, the compressor and the equipment bolted inside are Section 179 property in their own right.', watch: 'Almost every mile is business, which makes the mileage rate straightforward and generous here — but a van used for a weekly shop is not 100% business and claiming it as such invites the question. Parts bought for a specific job are deductible when used; stock carried in the van at year end is inventory.' },
  { key: 'nursing_agency', slug: 'nursing-agency', name: 'Nursing agency owner', lead: 'You employ clinicians who work in other people\'s facilities, which puts payroll, workers\' compensation and professional liability cover on your return rather than the hospital\'s. Malpractice cover for a nursing panel is priced on what they do and is deductible in full.', watch: 'Credentialing each clinician with each facility costs money and time, and both the fees and the staff who do it are deductible. Travel contracts bring stipends and housing, and whether those are tax-free to the clinician turns on their tax home rather than on your paperwork — but getting the documentation right protects both of you.' },

  /* Trades and services whose tax position is ordinary practice rather than a
     statutory quirk. These carry no citations because they assert no provision —
     the gate check lists any page that names one without linking to it. */
  { key: 'locksmith', slug: 'locksmith', name: 'Locksmith', lead: 'Your van is the shop and the key stock inside it is inventory, not an expense — blanks and cylinders come off when you fit them, not when you buy them.', watch: 'Most states license locksmiths and require a background check to do it; both the license and the check are deductible. Emergency call-outs make mileage large and badly recorded. Key-cutting machines, decoders and programming tools are Section 179 property, and vehicle programming equipment in particular costs more than most people expect to write off in one year.' },
  { key: 'pest_control', slug: 'pest-control', name: 'Pest control operator', lead: 'The chemicals and the person applying them are both regulated. State applicator licensing, the continuing education that renews it and the record-keeping it requires are all deductible, and none of them are optional.', watch: 'Product bought in bulk and held at year end is inventory rather than a deduction. Termite and damage warranties you issue create a liability that is not deductible until you actually do the work. Sprayers, rigs and monitoring equipment are Section 179 property.' },
  { key: 'pool_service', slug: 'pool-service', name: 'Pool service technician', lead: 'Route density is the whole economics of this trade, and mileage is the deduction that follows it. A tight route is more profitable and produces a smaller mileage claim; a scattered one is the reverse.', watch: 'Chlorine, acid and salt are supplies deductible as used, not when the pallet arrives. Repairs where you supply a pump or heater make you a retailer for that part, with the cost of the part as cost of goods. In most states the season is short enough that your income is concentrated in a few months while costs run all year.' },
  { key: 'tree_service', slug: 'tree-service', name: 'Tree service or arborist', lead: 'Insurance is the barrier to entry and the biggest fixed cost in the trade. General liability plus workers compensation on a climbing crew is priced on the risk, and both are deductible in full.', watch: 'Chippers, stump grinders, bucket trucks and climbing gear are Section 179 property. Hiring a crane for a single removal is deductible in full with nothing to depreciate. Storm work concentrates a year of income into a few weeks, which is worth planning quarterly payments around rather than being surprised by.' },
  { key: 'snow_removal', slug: 'snow-removal', name: 'Snow removal contractor', lead: 'Seasonal contracts are frequently paid up front, before a flake falls. On the cash basis that money is income when it arrives, so a November payment for a whole winter lands in the earlier tax year while most of the cost lands in the later one.', watch: 'Ploughs, spreaders and loaders are Section 179 property. Salt and de-icer held at year end is inventory. A light winter is a business risk rather than a deduction — there is no relief for revenue you contracted for and did not have to earn.' },
  { key: 'junk_removal', slug: 'junk-removal', name: 'Junk removal service', lead: 'Landfill and transfer station fees are the largest variable cost and are deductible in full. What you keep and resell rather than dumping is income at what you sell it for, and it is easy to forget that the free sofa became stock the moment you decided to list it.', watch: 'Trucks and trailers are business vehicles on actual costs. Crews are employees rather than contractors in nearly all cases. Hazardous or electronic waste carries its own disposal charges and often its own permits, both deductible.' },
  { key: 'moving_company', slug: 'moving-company', name: 'Moving company owner', lead: 'Moving across state lines makes you a federally regulated carrier, with operating authority and insurance filings that cost money annually and are deductible annually.', watch: 'Valuation coverage sold to a customer is your income, not money held for an insurer, unless you are genuinely acting as an agent for a separate policy. Packing materials are inventory until used. Crews are employees, and workers compensation on movers is priced accordingly.' },
  { key: 'tow_truck', slug: 'tow-truck', name: 'Tow truck operator', lead: 'A tow truck is well above the weight at which the annual passenger-car depreciation caps stop applying, so it is written off far faster than a saloon costing the same. That is the single biggest tax feature of the trade.', watch: 'Storage fees on an impounded vehicle accrue whether or not the owner ever collects it. On the cash basis you report them when paid, which for abandoned vehicles may be never — and a lien sale is a separate transaction with its own consequences. Rotation and police-list permits are deductible.' },
  { key: 'auto_detailer', slug: 'auto-detailer', name: 'Auto detailer', lead: 'Mobile detailing carries almost no rent and a lot of vehicle cost; a fixed bay is the reverse. Which one you run decides whether your largest deduction is mileage or premises.', watch: 'Compounds, sealants and coatings are supplies deductible as used. Ceramic coating certifications are deductible as maintaining a skill once you are trading. Water reclamation requirements in some jurisdictions bring equipment and permit costs, both deductible.' },
  { key: 'marine_mechanic', slug: 'marine-mechanic', name: 'Marine mechanic', lead: 'The season is short and the winter is long in most of the country, so income arrives in a few months while rent and tooling run all year. Basing quarterly payments on last year rather than on a spring forecast is what keeps that manageable.', watch: 'Manufacturer certifications for outboards and sterndrives are deductible and are what qualifies you for warranty work. Waste oil, coolant and antifouling disposal are regulated and deductible. Diagnostic software subscriptions per manufacturer add up and are ordinary costs. Winterisation and commissioning are the two weeks that carry the year, and both are labor with almost no parts against them. Haul-out and yard fees you pay to work on a boat ashore are deductible; the same fees rebilled to the owner are income and a deduction both. Dockside service means a workboat or a tender, which is a business asset in its own right.' },
  { key: 'rv_repair', slug: 'rv-repair', name: 'RV repair technician', lead: 'An RV is a vehicle, a small building and a set of gas appliances at once. That means certification across several trades — chassis, propane, electrical, roofing — and each certification and its renewal is deductible.', watch: 'Mobile service is where the margin is, and it makes the service van and its mileage a major deduction. Parts held for a job are inventory until fitted. Warranty work paid by a manufacturer is income when they pay, which is often long after the repair. Warranty work is the structural difference from other repair trades. Manufacturers pay published times rather than what the job took, so a hard job pays the same as an easy one and the shortfall is not a deduction — it is simply less income. Mobile service avoids the bay rent that fixed shops carry and turns the service van into the largest single asset. Roof resealing and delamination work are seasonal in a way engine work is not.' },
  { key: 'small_engine_repair', slug: 'small-engine-repair', name: 'Small engine repair', lead: 'The parts wall is the business and it is not a deduction. Carburettors, filters and blades sitting on the shelf at December 31 are inventory; they come off when they go on a machine.', watch: 'Seasonality runs in two directions — mowers in spring, snowblowers in autumn — which smooths the year better than most trades. Waste oil and fuel disposal are regulated and deductible. Pick-up and delivery makes mileage worth logging.' },
  { key: 'bike_shop', slug: 'bike-shop', name: 'Bike shop owner', lead: 'You are running two businesses in one shop. Selling bikes is retail with inventory and cost of goods sold; servicing them is a service with almost no stock and a much better margin. They are taxed differently line by line and are worth tracking separately.', watch: 'Model-year obsolescence is real and writing stock down requires it to actually be worth less, not merely last year\'s. Tools and workstands are Section 179 property. Sales tax applies to the bikes and, in many states, differently to the labor.' },
  { key: 'motorcycle_repair', slug: 'motorcycle-repair', name: 'Motorcycle repair shop', lead: 'Manufacturer-specific tooling and diagnostic equipment is the entry cost to working on any given marque, and all of it is Section 179 property deductible in the year you start using it.', watch: 'The riding season concentrates income into part of the year in most of the country, while rent runs all twelve months. Tyres, oil and parts on the shelf are inventory. Storage of customer bikes over winter is a separate service with its own income and, sometimes, its own insurance requirement.' },
  { key: 'upholsterer', slug: 'upholsterer', name: 'Upholsterer', lead: 'Fabric is the line that decides how this return reads. Bought for a named job it is cost of goods sold against that job; bought for the rack it is inventory until somebody chooses it, which can be years.', watch: 'Industrial machines, compressors and cutting tables are Section 179 property. Pick-up and delivery of furniture makes the van a real deduction. Antique and automotive work often carries higher insured values than general upholstery, and the insurance difference is deductible.' },
  { key: 'tailor', slug: 'tailor', name: 'Tailor or seamstress', lead: 'Alterations and making are different businesses for tax. Alterations are nearly pure service with a few dollars of thread and interfacing; making a garment from bought cloth makes you a manufacturer, with fabric as inventory until the piece is finished and sold.', watch: 'Industrial machines, sergers and steam presses are Section 179 property. Working from home is common in this trade and the home office is usually the largest deduction — the space has to be used regularly and exclusively, which a dining table is not.' },
  { key: 'dry_cleaner', slug: 'dry-cleaner', name: 'Dry cleaner', lead: 'Solvent is what makes this trade different. Handling, storing and disposing of it is regulated, permitted and inspected, and every part of that compliance cost is deductible — as is the equipment upgrade that reduces it.', watch: 'Machines are Section 179 property and a plant refit is a very large one-year deduction. Utilities are unusually high for the floor area and are deductible in full. Customer garments lost or damaged create a liability that is deductible when you actually settle it, not when the complaint arrives.' },
  { key: 'laundromat', slug: 'laundromat', name: 'Laundromat owner', lead: 'This is an equipment business, not a retail one. There is almost nothing to hold as stock; the machines are the asset and they are Section 179 property, so a re-equip can be written off in a single year.', watch: 'Water, gas and electricity are the dominant operating cost and are deductible in full. A card or app payment system replaces coin handling and is both an ordinary subscription and a piece of equipment. If you own the building, cost segregation splits out the plumbing, electrical and finishes into much shorter lives than the shell.' },
  { key: 'car_wash', slug: 'car-wash', name: 'Car wash owner', lead: 'Most of what you built is not building. Conveyor, brushes, blowers, pumps and the water reclamation plant depreciate over far shorter lives than the structure they sit in, and a cost segregation study is what separates them.', watch: 'Chemicals are supplies deductible as used. Unlimited wash memberships are income when the customer pays, not when they wash — a January annual pass is January income. Water and power are the largest running costs and are deductible in full.' },
  { key: 'home_inspector', slug: 'home-inspector', name: 'Home inspector', lead: 'Claims in this trade arrive years after the inspection, which makes the tail on your professional indemnity cover as important as the policy itself. Both are deductible, and dropping cover when you retire is how old inspections become personal liabilities.', watch: 'Thermal cameras, moisture meters and drones are Section 179 property. Report-writing software and license renewal are ordinary annual costs. Mileage between inspections is deductible and, since almost every job is somewhere different, it is one of the larger lines. Ancillary services are where the margin is and each brings its own licensing: radon, mold, sewer scoping and termite work are often separate state certifications, all deductible. If you bought a franchise rather than trading under your own name, the initial fee is not a deduction — it is amortized over fifteen years — while the ongoing royalty is deductible as you pay it.' },
  { key: 'land_surveyor', slug: 'land-surveyor', name: 'Land surveyor', lead: 'A GPS rover, a robotic total station and a drone are the capital of this business, and all of it is Section 179 property — the whole cost comes off in the year it goes into service rather than across a decade.', watch: 'Licensing is per state, so working near a border means several registrations and several sets of continuing education, each deductible. Professional liability cover is priced on boundary work for good reason and is deductible in full. Field crew are employees. Liability here has no practical end date: a boundary you set can be litigated decades later, which is why the profession carries records rather than discarding them and why the storage of those records is itself a deductible cost. Research time at county recorders and title offices is billable work with almost no expense against it. Crew wages are the largest line for anyone running more than a one-person operation, and field crews are employees rather than contractors in essentially every case.' },
  { key: 'appraiser', slug: 'appraiser', name: 'Property appraiser', lead: 'This is a home office and a car, and very little else. That makes those two the whole deduction — and it makes getting the home office right worth more here than in trades with premises and equipment to write off.', watch: 'Licensing runs per state with continuing education attached, all deductible. Data and comparable-sales subscriptions are ordinary costs. Professional indemnity cover matters because appraisals are relied on by lenders, and claims can arrive long after the report.' },
  { key: 'mortgage_broker', slug: 'mortgage-broker', name: 'Mortgage broker', lead: 'You are paid at closing, not at application, so the work and the money can fall months and sometimes tax years apart. A pipeline full of applications at December 31 is not income yet.', watch: 'Lead generation is the largest controllable cost and is fully deductible. Licensing under the national registry, per state, with continuing education attached, is deductible annually. A commission clawed back on an early payoff is a deduction in the year you repay it rather than a correction to the year you earned it.' },
  { key: 'title_agent', slug: 'title-agent', name: 'Title or closing agent', lead: 'Escrow funds are never yours. They do not appear on your return in either direction, and running them through an operating account is a licensing problem before it is a tax problem.', watch: 'On a title premium you keep an agent\'s share and remit the rest to the underwriter — only your share is income. Errors and omissions cover and the fidelity bond are both required and both deductible. Search and examination software and county record subscriptions are ordinary costs.' },
  { key: 'property_manager', slug: 'property-manager', name: 'Property manager', lead: 'Rent you collect belongs to the owner. Only your management fee is income, and only your own costs are deductions — a repair you arrange and pass on is the owner\'s expense, not yours, unless you genuinely bore it.', watch: 'Trust account rules in most states require owner funds to be held separately, and the licensing consequence of getting that wrong is worse than the tax one. Management software, tenant screening and per-state licensing are ordinary deductible costs. Vehicle use across a portfolio is a real mileage claim.' },
  { key: 'grant_writer', slug: 'grant-writer', name: 'Grant writer', lead: 'Most funders prohibit paying for grant writing out of the grant itself, and contingency fees are widely barred outright. That pushes this work onto retainers and hourly billing, which means income arrives steadily rather than in lumps.', watch: 'Funder databases and research subscriptions are the main overhead and are ordinary deductible costs. Working for nonprofits does not make your own income tax-exempt — you are a vendor, not a charity, and a charity that pays you $600 or more should still be issuing you a 1099-NEC even though plenty do not. Federal grants carry their own compliance vocabulary, and a client asking you to work within an approved indirect cost rate is describing their constraint, not yours: your fee is ordinary income whichever budget line it comes from.' },
  { key: 'technical_writer', slug: 'technical-writer', name: 'Technical writer', lead: 'Long single-client contracts are the norm here and they are also what makes reclassification a live risk: full-time hours for one company, on their tools, to their schedule, looks like employment whatever the contract says.', watch: 'Authoring tools, documentation platforms and diagramming software are ordinary subscriptions. The home office is usually the biggest deduction. Work billed on delivery rather than monthly can put a whole project\'s income into one tax year.' },
  { key: 'college_consultant', slug: 'college-consultant', name: 'College admissions consultant', lead: 'A package sold in the spring for a cycle finishing the following spring is income when the family pays it, not when the work is done. That routinely puts the money in one tax year and most of the effort in the next.', watch: 'Campus visits are business travel where the purpose is genuinely professional. Professional association membership and training are deductible. Several states regulate this work, and where licensing applies it is deductible.' },
  { key: 'music_teacher', slug: 'music-teacher', name: 'Music teacher', lead: 'Where you teach decides your biggest deduction. A home studio used only for teaching is a home office claim; travelling to students makes mileage the largest line instead. Doing both means tracking both.', watch: 'Instruments used professionally are Section 179 property at the business-use percentage — an instrument you also play for pleasure is a split, not a full claim. Sheet music, method books and platform subscriptions are ordinary costs. Recital hall hire is deductible; the flowers are marketing.' },
  { key: 'dj', slug: 'dj', name: 'DJ', lead: 'You do not own your music library, you license it, and the subscription that keeps it legal for commercial use is an ongoing deductible cost rather than a one-off purchase.', watch: 'Controllers, speakers, lighting and cases are Section 179 property. Venues increasingly require proof of liability cover, which is deductible. Deposits taken for next summer\'s weddings are income when they arrive, which is why a busy booking season can be taxed a year before it is worked.' },
  { key: 'wedding_officiant', slug: 'wedding-officiant', name: 'Wedding officiant', lead: 'There is almost nothing to deduct here, which is exactly why the few things there are matter. Travel to ceremonies, registration where your state or county requires it, and the home office you write ceremonies in are most of the list.', watch: 'Fees are self-employment income whether or not anyone issues you a form, and most couples will not. If you are ordained and also serve a congregation, the clergy rules are a completely different regime — see the clergy page, because the dual status there changes how the tax is paid.' },
  { key: 'personal_chef', slug: 'personal-chef', name: 'Personal chef', lead: 'Groceries you buy to cook for a client are cost of goods sold. The 50% limit that applies to business meals has nothing to do with them: that rule is about meals you eat, not food you sell, and applying it would halve your largest deduction for no reason.', watch: 'Whether you bill groceries separately or fold them into the fee changes your gross receipts but not your profit. Knives, equipment and transport containers are deductible. Food handling certification and, in some states, a license are ordinary costs, and cooking in a client\'s kitchen rather than your own usually avoids the commercial kitchen requirement.' },
  { key: 'drone_operator', slug: 'drone-operator', name: 'Drone operator', lead: 'Flying commercially requires a federal remote pilot certificate, and both the training and the recurrent testing that keeps it valid are deductible — they maintain a qualification you already use to earn.', watch: 'Airframes, batteries, payloads and controllers are Section 179 property. Aviation liability cover is a specialist product and is deductible. Waivers for night or beyond-line-of-sight operations cost time rather than much money, but the consultants who prepare them are deductible.' },
  { key: 'it_consultant', slug: 'it-consultant', name: 'IT consultant or managed service provider', lead: 'Licenses you buy and rebill run through your books as income and as a deduction. A managed service provider passing through hundreds of seats of software looks far larger by turnover than it is by margin, and that affects lenders, thresholds and the forms you receive.', watch: 'Cyber liability cover is the deduction most providers do not carry until a client contract demands it. Certifications and vendor partner fees are deductible as maintaining skills you already sell. Equipment held to deploy at clients is inventory until it is deployed.' },
  { key: 'cybersecurity_consultant', slug: 'cybersecurity-consultant', name: 'Cybersecurity consultant', lead: 'The certifications are the credential and they all expire. Renewal fees and the continuing education hours behind them recur every cycle, and all of it is deductible because it maintains a qualification you already trade on.', watch: 'Testing hardware, lab equipment and licensed tooling are Section 179 property or ordinary subscriptions depending on what they are. Professional indemnity cover matters more here than in most consulting because the work touches client systems directly. Retainers paid in advance are income when received.' },
  { key: 'court_reporter', slug: 'court-reporter', name: 'Court reporter', lead: 'You are paid for the transcript, not the day, and transcripts are often ordered and paid for weeks or months after the proceeding. The work and the money routinely fall in different quarters and sometimes different years.', watch: 'Stenotype machines and computer-aided transcription software are Section 179 property and both are expensive. Certification and its continuing education are deductible. Realtime and captioning work usually pays better and requires further certification, also deductible.' },
  { key: 'sign_language_interpreter', slug: 'sign-language-interpreter', name: 'Sign language interpreter', lead: 'The overhead is almost nothing and the mileage is substantial. Assignments are short and scattered across a region, so the driving between them is the largest deduction in the business and the one most easily lost by not logging it.', watch: 'National certification and the continuing education that maintains it are deductible. Video relay work from home turns the home office into a real deduction and the internet connection into a business cost at the business-use percentage. Agency work usually makes you a contractor, but check — some agencies engage interpreters as employees.' },
  { key: 'process_server', slug: 'process-server', name: 'Process server', lead: 'Mileage is the business. Attempts at an address that turns out to be wrong still cost the drive, and they are still deductible — but only if the log distinguishes them from personal trips.', watch: 'Skip-trace and public records databases are the overhead nobody outside the trade expects, and they are ordinary deductible subscriptions. Licensing and bonding are required in many states and both are deductible. Body cameras and GPS-stamped photo apps are equipment and subscriptions respectively.' },
  { key: 'bail_bondsman', slug: 'bail-bondsman', name: 'Bail bondsman', lead: 'Collateral you hold is not your money and is not income. The premium is. Mixing the two overstates a year badly, and returning collateral later does not undo it.', watch: 'A forfeiture you actually pay is deductible when you pay it, not when the defendant fails to appear. Recovery costs to bring someone back are ordinary business expenses. State licensing, surety appointment and continuing education are all deductible.' },
  { key: 'auctioneer', slug: 'auctioneer', name: 'Auctioneer', lead: 'What the hammer falls at is the consignor\'s money. Only your commission and the buyer\'s premium are income, and running gross proceeds through your own books makes a modest business look enormous and your forms unreconcilable.', watch: 'Buying lots for your own account makes you a dealer for those lots, with inventory and ordinary income rather than commission. Licensing and bonding are required in most states and are deductible. Online platform fees, catalogue photography and marketing are ordinary costs.' },
  { key: 'jeweler', slug: 'jeweler', name: 'Jeweller', lead: 'Your stock is capital, not a deduction. Metal and stones sitting in the safe at December 31 are inventory however much they cost, and they come off only when a piece sells.', watch: 'Jewellers block insurance is a specialist product and is deductible in full, as is the safe and the alarm. Benches, lasers, casting and CAD equipment are Section 179 property. Repair and remodelling work is a service business alongside the retail one, with much less capital behind it.' },
  { key: 'printing_3d', slug: '3d-printing-service', name: '3D printing service', lead: 'Printers are Section 179 property and come off in the year they start running. Resin and filament are supplies deductible as used — including everything consumed by prints that failed, which is a real and deductible cost rather than a mistake to hide.', watch: 'Design work billed alongside printing is a service with no materials against it and a very different margin. Selling finished goods rather than a printing service makes you a manufacturer, with inventory. Resin handling and disposal is regulated in some jurisdictions and those costs are deductible.' },

  /* Positions with a statutory rule at their center. Each cites the provision. */
  { key: 'landlord_residential', slug: 'landlord', name: 'Residential landlord', lead: 'Rental losses are passive by default, which means they sit unused against your salary no matter how real they are. There are exactly two ways out and most landlords qualify for neither without planning for it.', watch: 'The first exit is the $25,000 allowance: actively participate — own at least 10% and make the real decisions on tenants and rents — and you can take up to $25,000 of losses against other income. It shrinks by 50 cents for every dollar of income over $100,000 and is gone at $150,000. The second is real estate professional status, which needs more than half your working time and over 750 hours in property, and even then you must materially participate in each property unless you file an election to treat them all as one activity. Depreciation runs over 27.5 years for residential property, and it is not optional — sell without having claimed it and the recapture is calculated as though you had.' },
  { key: 'daycare_provider', slug: 'daycare-provider', name: 'Home daycare provider', lead: 'Every other home business has to use the space exclusively for work. Daycare does not — it is the one statutory exception, so a living room the children use by day and your family uses by night still qualifies. That single rule is worth more than every other deduction on this page.', watch: 'You calculate it twice over: the share of your home used, multiplied by the share of the year\'s hours it was used for daycare. The denominator is all 8,760 hours in the year, not the hours you were open. You must hold a state license, have applied for one, or be exempt — a license refused or revoked ends the deduction entirely. Meals are the second gift: rather than keeping food receipts you can claim standard rates per breakfast, lunch, dinner and snack, capped per child per day, with your own children never counting. You still need an attendance and meal log.' },
  { key: 'household_employer', slug: 'nanny-employer', name: 'Household employer', lead: 'If you pay someone $3,000 or more in 2026 to work in your home — a nanny, a housekeeper, a carer — you are their employer. Not their client, not a hirer of a contractor. Their employer, with Social Security and Medicare to withhold and to match.', watch: 'It is 6.2% plus 1.45% taken from their pay and the same again from you, reported on Schedule H filed with your own Form 1040 rather than on any business return. Unemployment tax is a separate test at $1,000 in any quarter, not the $3,000 one. Calling the arrangement contracting almost never survives scrutiny, because you control how the work is done in your own home — and getting it wrong surfaces years later when the worker claims unemployment or Social Security credit. Note this is a household obligation, not a business deduction: none of it is deductible unless the care qualifies you for the dependent care credit.' },
  { key: 'horse_business', slug: 'horse-trainer', name: 'Horse trainer or breeder', lead: 'The hobby loss rule is the whole tax question in this business. Ordinary trades are presumed to be run for profit if they made money in three of the last five years. Horses get their own longer test: two profitable years out of seven.', watch: 'That extra latitude exists because the code accepts that breeding, training, showing and racing take longer to turn a profit — but it is a presumption, not a shelter. Fail it and you are not automatically a hobby; pass it and the IRS can still argue otherwise. What decides it in practice is whether you behave like a business: separate accounts, a written plan, records that show you responded to losses by changing something. Breeding stock is a depreciable asset rather than an expense; horses bought to resell are inventory; a horse you raised yourself has no cost basis at all.' },
  { key: 'oil_gas_operator', slug: 'oil-gas-working-interest', name: 'Oil and gas working interest owner', lead: 'This is the widest exception in the passive loss rules and almost nobody outside the industry knows it exists. A working interest in an oil or gas property is not a passive activity however few hours you put into it — so the losses can offset your salary, which a rental property of identical passivity cannot.', watch: 'The condition is the form of ownership: you must hold it directly or through something that does not limit your liability, such as a general partnership interest. Hold the same well through an LLC or as a limited partner and the exception vanishes. Intangible drilling costs — the labor and services with no salvage value, usually most of a well\'s cost — can be deducted in the year incurred rather than capitalized, but the election is made on the first return where such costs arise and binds every year after. Say nothing on that first return and you have elected to capitalize, irrevocably. Once losses have been allowed, later income from the same property is recharacterised as non-passive too.' },

  { key: 'day_trader', slug: 'day-trader', name: 'Day trader', lead: 'Trading profits are not self-employment income. That is unusual and it cuts both ways: no 15.3% on the gains, and no earned income either — so nothing to base a solo 401(k) on and nothing counting toward Social Security.', watch: 'The mark-to-market election is the one that matters and the deadline traps people every year: you elect it by the due date of the PRIOR year’s return, without extensions. It cannot be made retroactively once you have had a bad year. Make it and your positions are treated as sold at year end, gains and losses become ordinary rather than capital, the wash sale rules stop applying and the $3,000 annual cap on deducting capital losses disappears. Being a trader at all requires substantial, continuous and regular activity aimed at daily price movements — an investor holding for appreciation does not qualify however large the account.' },
  { key: 'professional_gambler', slug: 'professional-gambler', name: 'Professional gambler', lead: 'This changed against you for 2026 and it is the most severe change in the code this year. Only 90% of your wagering losses are now deductible — so a gambler who wins $500,000 and loses $500,000, breaking exactly even, deducts $450,000 and pays tax on $50,000 of income that does not exist.', watch: 'Gambling full time, in good faith, with regularity and for a livelihood is a trade or business, which is what lets you deduct at all. But losses have never been allowed to exceed winnings in a year, and the new rule folds your non-wagering business costs — travel, data, tournament entries — into the same 90% limited bucket. There is no carry-forward of the disallowed 10%. Record-keeping per session is what makes any of this survive scrutiny, and it is the thing recreational players never do.' },
  { key: 'antiques_dealer', slug: 'antiques-dealer', name: 'Antiques or coin dealer', lead: 'The 28% collectibles rate is not yours. It caps the tax an investor pays on art, coins, stamps or antiques held over a year — but your pieces are stock in trade, not capital assets, so you pay ordinary rates and self-employment tax on top.', watch: 'That makes the dealer-or-investor line the most consequential fact about your return, and it is decided on the facts rather than by anything you file. Buying to resell, holding briefly, advertising, doing it continuously — all point to dealing. Someone can be both: a dealer in the shop stock and an investor in a personal collection held separately, provided the two are genuinely kept apart. Stock is not deductible when bought, only when sold, so a strong buying year with a slow selling year is taxed as if it went well.' },
  { key: 'franchise_owner', slug: 'franchise-owner', name: 'Franchise owner', lead: 'The check you wrote to buy the franchise is not a deduction. It is amortized over fifteen years — and it is fifteen regardless of whether your agreement runs for ten, twenty or in perpetuity.', watch: 'Renewal is treated as buying it again and starts its own fresh fifteen-year period. Ongoing royalties are different: where they are contingent on productivity or use and payable in substantially equal amounts across the agreement, they are deducted as you pay them rather than added to the fifteen-year pot. The distinction between an amount that is really part of the purchase price and one that is really rent for using the brand is worth getting right before you sign, because it is far harder to argue afterwards.' },
  { key: 'game_developer', slug: 'game-developer', name: 'Game or app developer', lead: 'This got better for 2026 and it matters more here than almost anywhere. Development work done in the United States is deductible in the year you pay for it again, rather than being spread across five years the way it was for the last few. Work done abroad still has to be spread — over fifteen.', watch: 'For a studio spending most of its money on people, that is the difference between a deduction now and a deduction mostly in future years you may not reach. You can still elect to spread domestic costs over at least sixty months if a loss is no use to you this year. Platform revenue shares are not your income — what the store keeps never reaches you — but read the statement, because some report gross and some net. Contractors paid $600 or more in a year need a 1099-NEC from you.' },

  { key: 'barber', slug: 'barber', name: 'Barber', lead: 'Two things changed for 2026 and both are in your favour. Tips are now partly deductible — up to $25,000 of them — and the employer credit for payroll tax on tips, which used to belong to restaurants alone, now covers barbering.', watch: 'The tips deduction reduces income tax only. It does not touch self-employment tax, so the 15.3% still applies to every dollar. It shrinks by $100 for every $1,000 of income over $150,000 and, if you are self-employed, it cannot exceed the net income of the business. The employer credit is different again: it is only worth something if you have employees on payroll, and it uses the current $7.25 minimum wage rather than the frozen $5.15 figure the food trade is stuck with. A booth renter with no staff claims the deduction and not the credit.' },
  { key: 'nail_technician', slug: 'nail-technician', name: 'Nail technician', lead: 'Nail care is named specifically in both of 2026\'s tip changes: in the list of occupations whose tips can be deducted, and in the extension of the employer payroll tax credit beyond restaurants for the first time.', watch: 'Product is the thing to watch. Gels, acrylics and polish bought in bulk are supplies deductible as you use them; retail product sold to clients is stock with cost of goods against it, and usually sales tax on top. Ventilation and extraction equipment is both a regulatory requirement in many states and Section 179 property. Booth rent is deductible and is also what makes you self-employed rather than employed — nobody is withholding anything from your takings.' },
  { key: 'esthetician', slug: 'esthetician', name: 'Esthetician', lead: 'Esthetics is named in both of 2026\'s tip changes — the deduction for tips received and the employer credit for payroll tax on them. It is also a trade where the equipment costs more than the room it sits in.', watch: 'Lasers, microneedling pens and light devices are Section 179 property, deductible in the year they go into service, and the manufacturer training that lets you use them is deductible separately as maintaining a skill you already sell. Retail skincare sold alongside treatments is stock, not supplies, with cost of goods and usually sales tax. Where a treatment crosses into medical territory, the supervising practitioner arrangement brings its own costs and its own insurance, both deductible.' },
  { key: 'tattoo_artist', slug: 'tattoo-artist', name: 'Tattoo artist', lead: 'Tattooing is on Treasury\'s list of occupations whose tips qualify for the new deduction, which is worth knowing because a great deal of this trade is tipped and almost none of it is reported by anyone but you.', watch: 'The deduction is capped at $25,000, phases out above $150,000 of income, and reduces income tax only — self-employment tax still applies to every dollar of it. Machines, power supplies and needles are equipment and supplies respectively. Sharps disposal and bloodborne pathogen certification are regulatory requirements and recurring deductible costs. Custom design time billed separately is service income with nothing to set against it, which is why it is the most profitable hour in the day.' },
  { key: 'gym_owner', slug: 'gym-owner', name: 'Gym or fitness studio owner', lead: 'This is the distinction that matters and it is widely got wrong. Athletics is a specified service trade — but the regulation means people competing and the coaches who train them, and it expressly excludes running the equipment and the facilities. A gym or studio is not a specified service business, and health clubs providing exercise and conditioning are named as outside it.', watch: 'So the 20% deduction on business profit is not withdrawn from you by income alone the way it is from a personal trainer coaching competitive athletes. Above the threshold it is still limited by what you pay in wages and what you have invested in property, which a staffed gym full of equipment usually clears. Memberships sold annually are income when paid, not month by month. Equipment is Section 179 property and a fit-out is a very large one-year deduction.' },
  { key: 'streamer', slug: 'streamer', name: 'Streamer or content creator', lead: 'The word on the button decides nothing. A viewer donation is a gift only where it comes from detached and disinterested generosity — and a payment made for a shout-out, an alert or continued content is not that. Subscriptions, bits, tips and sponsorships are all income, and for anyone running a channel as a business they are self-employment income too.', watch: 'There is better news on the 20% deduction. Performing arts is a specified service trade that loses it at higher incomes, but the regulation expressly excludes people who broadcast or otherwise disseminate video or audio to the public — distribution is not performance. A streamer is generally outside that category even where a musician performing on the same platform is inside it. Capture cards, cameras, lighting and computers are Section 179 property at the business-use percentage, and the machine you also game on personally is a split rather than a full claim.' },
  { key: 'commercial_fisherman', slug: 'commercial-fisherman', name: 'Commercial fisherman', lead: 'If you are paid a share of the catch on a boat whose normal operating crew is fewer than ten, you are not an employee. That share is self-employment income on Schedule C with self-employment tax on it, and nobody is withholding a cent.', watch: 'Ten or more crew, or cash beyond a small per-trip amount unconnected to the catch, and you are back to being an employee. The compensating advantage is income averaging: fishing qualifies alongside farming, so an exceptional season can be spread back across the three prior years at those years\' rates on Schedule J. It does not reduce self-employment tax, only income tax. Vessels, gear and electronics are Section 179 property; permits and quota are intangible assets rather than expenses.' },
  { key: 'logger_timber', slug: 'timber-logging', name: 'Timber or logging operator', lead: 'Cut your own timber and sell the lumber and the whole profit is ordinary income. There are two ways out, and both convert part of it to a much better rate.', watch: 'The first is an election to treat the cutting itself as a sale, at the timber\'s market value on the first day of the tax year — everything after that is ordinary business profit, and everything up to it is capital. It binds all your timber for that year and every year after, so it is not a decision to make lightly. The second is disposing of timber while retaining an economic interest, which gets the same treatment without the election. Either way the gain is section 1231 rather than automatic long-term capital gain. Depletion here is cost depletion only — never the percentage method that mining uses — computed as a unit rate against the volume you actually cut.' },
  { key: 'beekeeper', slug: 'beekeeper', name: 'Beekeeper', lead: 'Beekeeping is farming for tax, so it belongs on Schedule F rather than Schedule C, and the whole farm regime comes with it: income averaging across three prior years, the credit for federal fuel tax on off-highway use, and the prepaid supplies limit.', watch: 'Pollination contracts are farm income like honey sales. Hives, extractors and bottling equipment are Section 179 property; queens and packages bought to expand are usually treated as breeding stock rather than an expense. Losses are where care is needed: keeping bees for pleasure is not a farming business at all, and the profit presumption asks whether you made money in three of the last five years. A run of loss years does not settle it, but it starts the argument.' },
  { key: 'voice_actor', slug: 'voice-actor', name: 'Voice actor', lead: 'Your home booth is the business. Treatment, microphones, interfaces and the acoustic work that makes a spare room usable are Section 179 property, deductible in the year the booth starts earning.', watch: 'On the 20% deduction, voice work generally falls within performing arts, which is withdrawn above the income thresholds — the regulation names actors and entertainers rather than voice actors specifically, so this is inference rather than a stated rule. Licensing your voice for a fee is separate and explicit: that is one of the three things the reputation-and-likeness category actually covers, alongside endorsements and appearance fees. It matters increasingly as synthetic voice licensing becomes a real line of income. Agent commission is deductible in full and comes off a gross figure you never received.' },
];

export function professionFor(slug: string): Profession | null {
  return PROFESSIONS.find((p) => p.slug === slug) ?? null;
}

export function professionData(key: string): Record<string, any> {
  return RAW[key] ?? {};
}

